    // Robust CSV parser (handles quoted fields, escaped quotes "", different row lengths).
    // Adapts to chosen delimiter. Returns array of rows (each row is array of strings).
    function parseCSV(text, delimiter) {
      // Normalize line endings
      text = text.replace(/\\r\\n/g, '\\n').replace(/\\r/g, '\\n');
      var rows = [];
      var cur = [];
      var field = '';
      var inQuotes = false;
