    // More permissive parser that supports CRLF and flexible handling.
    // Improved parser: state machine that accepts multi-line quoted fields etc.
    function parseCSVRobust(text, delimiter) {
      // Normalize CRLF
      text = text.replace(/\\r\\n/g, '\\n').replace(/\\r/g, '\\n');
      if (delimiter === '\\\\t' || delimiter === '\\t') delimiter = '\\t';
      var rows = [];
      var row = [];
      var field = '';
      var inQuotes = false;
      for (var i = 0; i < text.length; i++) {
        var ch = text[i];
        if (inQuotes) {
          if (ch === '"') {
            // If next char is also quote, it's an escaped quote
            if (i + 1 < text.length && text[i+1] === '"') {
              field += '"';
              i++;
            } else {
              inQuotes = false;
            }
          } else {
            field += ch;
          }
        } else {
          if (ch === '"') {
            inQuotes = true;
          } else if (ch === delimiter) {
            row.push(field);
            field = '';
          } else if (ch === '\\n') {
            row.push(field);
            rows.push(row);
            row = [];
            field = '';
          } else {
            field += ch;
          }
        }
      }
      // push last
      row.push(field);
      // If the last character was a newline, we will have already pushed a row and row will be ['']
      // To keep consistent behavior, add last row if non-empty or if file ended with newline (we include trailing empty row)
      // We'll always push last row (could be empty)
      rows.push(row);
      // If the CSV is a single empty string (user didn't type anything), return empty array
      if (rows.length === 1 && rows[0].length === 1 && rows[0][0] === '') return [];
      return rows;
    }

    function inferType(value) {
      if (value === '') return ''; // empty
      // Try number
      if (!isNaN(value) && value.trim() !== '') return Number(value);
      // Try boolean
      var vlow = value.trim().toLowerCase();
      if (vlow === 'true') return true;
      if (vlow === 'false') return false;
      return value;
    }

    function renderTable(rows, options) {
      var out = document.createElement('div');
      out.innerHTML = ''; // container
      if (!rows || rows.length === 0) {
        var m = document.createElement('div');
        m.className = 'meta';
