          var td = document.createElement('td');
          var raw = norm[i][j] !== undefined ? norm[i][j] : '';
          if (tryTypes) {
            var v = inferType(raw);
            // render properly: numbers/booleans as text nodes, strings as text
            td.textContent = (v === '' ? '' : String(v));
          } else {
            td.textContent = raw;
          }
          tr.appendChild(td);
        }
        tbody.appendChild(tr);
      }

      table.appendChild(thead);
      table.appendChild(tbody);
      out.appendChild(table);

      var meta = document.createElement('div');
      meta.className = 'meta';
      meta.textContent = 'Rows: ' + rows.length + ', Columns: ' + maxCols + (hasHeader ? ' (first row used as header)' : '');
      out.appendChild(meta);

      return out;
    }

    function escapeHtml(s) {
      return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    }

    document.getElementById('parseBtn').addEventListener('click', function () {
      var text = document.getElementById('csvInput').value;
