    input[type="text"], select { padding:6px 8px; border-radius:6px; border:1px solid #ccd0d5; }
    footer { margin-top:16px; font-size:12px; color:#666; }
    @media (max-width:720px){ #controls { flex-direction:column; } .controls-right{ width:100%; } }
  </style>
</head>
<body>
  <h1>Robust CSV Parser</h1>
  <div id="controls">
    <div class="controls-left">
      <label for="csvInput">CSV input</label>
      <textarea id="csvInput" placeholder='Paste CSV here. Example:
"Name","Age","Notes"
"Smith, John",30,"Likes ""quotes"" and new
lines"
Doe,25,"No notes"'></textarea>
      <div style="display:flex; gap:8px;">
        <button id="parseBtn">Parse</button>
        <button id="clearBtn" class="secondary">Clear</button>
        <button id="pasteExample" class="secondary">Load Example</button>
        <div style="flex:1"></div>
      </div>
      <div class="small">Options: you can change delimiter (default comma) or whether to trim unquoted fields.</div>
    </div>
    <div class="controls-right">
      <label for="delimiter">Delimiter</label>
      <input id="delimiter" type="text" value="," maxlength="1" title="Single-character field delimiter">
      <label for="trimUnquoted"><input id="trimUnquoted" type="checkbox" checked> Trim unquoted fields</label>
      <label for="hasHeader"><input id="hasHeader" type="checkbox" checked> First row is header</label>
      <label for="maxRows">Max rows to show (0 = all)</label>
      <input id="maxRows" type="number" value="0" min="0">
    </div>
  </div>

  <div id="tableWrap" aria-live="polite"></div>
  <div id="error" class="error" role="status" aria-live="assertive"></div>
  <footer>Parser supports quoted fields with escaped quotes as "" and newlines inside quoted fields.</footer>

  <script>
  (function(){
    const input = document.getElementById('csvInput');
    const parseBtn = document.getElementById('parseBtn');
    const clearBtn = document.getElementById('clearBtn');
    const pasteExample = document.getElementById('pasteExample');
    const tableWrap = document.getElementById('tableWrap');
    const errorDiv = document.getElementById('error');
    const delimiterEl = document.getElementById('delimiter');
    const trimUnquotedEl = document.getElementById('trimUnquoted');
    const hasHeaderEl = document.getElementById('hasHeader');
    const maxRowsEl = document.getElementById('maxRows');

    // Robust CSV parser:
    // - Single-character delimiter (default comma)
    // - Supports quoted fields: " ... "
    // - Escaped quotes inside quoted fields are represented by double quotes: ""
    // - Supports newlines inside quoted fields
    // - Preserves empty fields
    function parseCSV(text, delimiter=',', options={trimUnquoted:true}) {
      if (delimiter.length !== 1) throw new Error('Delimiter must be a single character');
      const rows = [];
      let i=0;
      const len = text.length;
      let fieldBuf = '';
      let row = [];
      let inQuotes = false;
      let fieldQuoted = false; // whether current field started with a quote
      while (i < len) {
        const ch = text[i];

        if (inQuotes) {
          if (ch === '"') {
            // Possible end of quote or escaped quote
            const next = text[i+1];
            if (next === '"') {
              // Escaped quote -> append one quote and skip the escape
              fieldBuf += '"';
              i += 2;
              continue;
            } else {
              // End of quoted section
              inQuotes = false;
              i++;
              continue;
            }
          } else {
            // Any character (including newlines) inside quotes
            fieldBuf += ch;
            i++;
            continue;
          }
        } else {
          // Not in quotes
          if (ch === delimiter) {
            // field boundary
            let finalField = fieldBuf;
            if (fieldQuoted) {
              // quoted: do not trim; what was inside is literal
            } else {
              if (options.trimUnquoted) finalField = finalField.trim();
            }
            row.push(finalField);
            fieldBuf = '';
            fieldQuoted = false;
            i++;
            continue;
          } else if (ch === '\r') {
            // Could be \r\n or lone \r
            // finish field and row
            let finalField = fieldBuf;
            if (fieldQuoted) {
              // unmatched quotes: treat remaining as literal (or could error)
            } else {
              if (options.trimUnquoted) finalField = finalField.trim();
            }
            row.push(finalField);
            fieldBuf = '';
            fieldQuoted = false;
            // consume \r and optional \n
            if (text[i+1] === '\n') i += 2; else i++;
            rows.push(row);
            row = [];
            continue;
          } else if (ch === '\n') {
            // finish field and row
            let finalField = fieldBuf;
            if (fieldQuoted) {
              // unmatched quotes: treat remaining as literal
            } else {
              if (options.trimUnquoted) finalField = finalField.trim();
            }
            row.push(finalField);
            fieldBuf = '';
            fieldQuoted = false;
            i++;
            rows.push(row);
            row = [];
            continue;
          } else if (ch === '"') {
            // Start of quoted field IF field is empty (ignoring whitespace if trimUnquoted is true)
            // But allow quotes in the middle of a field only if fieldBuf is empty (or only whitespace and trim option)
            let allowStart = false;
            if (fieldBuf === '') {
              allowStart = true;
            } else if (options.trimUnquoted && /^\s*$/.test(fieldBuf)) {
              // only whitespace so far
              fieldBuf = ''; // drop the whitespace, treat as start quote
              allowStart = true;
            }
            if (allowStart) {
              inQuotes = true;
              fieldQuoted = true;
              i++;
              continue;
            } else {
              // a quote in the middle of an unquoted field: treat as literal
              fieldBuf += '"';
              i++;
              continue;
            }
          } else {
            // regular character
            fieldBuf += ch;
            i++;
            continue;
          }
        }
      } // end while

      // End of input: finalize last field and row
      // If we ended while still in quotes, we treat the unclosed quote as literal (append no extra)
      let finalField = fieldBuf;
      if (!fieldQuoted) {
        if (options.trimUnquoted) finalField = finalField.trim();
      }
      row.push(finalField);
      // If the text ends with a trailing delimiter, there will be an empty final field; handled above
      // If the input is empty string, result should be [[]] => treat as no rows
      // We'll handle common expectations: if input is empty -> empty array
      if (!(row.length === 1 && row[0] === '' && rows.length === 0 && text.length === 0)) {
        rows.push(row);
      } else {
        // empty input -> zero rows
      }

      return rows;
    }

    function renderTable(data, options={hasHeader:true, maxRows:0}) {
      tableWrap.innerHTML = '';
      errorDiv.textContent = '';
      if (!data || data.length === 0) {
        tableWrap.innerHTML = '<div style="padding:12px;color:#444">No data to display.</div>';
        return;
      }
      const maxRows = options.maxRows && options.maxRows > 0 ? options.maxRows : data.length;
      const table = document.createElement('table');
      const thead = document.createElement('thead');
      const tbody = document.createElement('tbody');

      // Determine column count (max across rows)
      let cols = 0;
      data.forEach(r => { if (r.length > cols) cols = r.length; });

      // Build header
      let headerRow = null;
      if (options.hasHeader) {
        headerRow = data[0];
      } else {
        // synthesize header: Col 1, Col 2...
        headerRow = [];
        for (let c=0;c<cols;c++) headerRow.push('Column ' + (c+1));
      }
      const trHead = document.createElement('tr');
      for (let c=0;c<cols;c++) {
        const th = document.createElement('th');
        th.textContent = headerRow[c] !== undefined && headerRow[c] !== '' ? headerRow[c] : ' ';
        trHead.appendChild(th);
      }
      thead.appendChild(trHead);

      // Build body rows
      const startRow = options.hasHeader ? 1 : 0;
      const endRow = Math.min(data.length, startRow + maxRows);
      for (let r = startRow; r < endRow; r++) {
        const tr = document.createElement('tr');
        const row = data[r];
        let isEmpty = true;
        for (let c=0;c<cols;c++) {
          const td = document.createElement('td');
          const cell = row[c] !== undefined ? row[c] : '';
          if (cell !== '') isEmpty = false;
          // Preserve newlines inside cells visually
          const lines = ('' + cell).split('\\n');
          // Use text node with whitespace preserved by replacing \n with line breaks
          // Create a fragment
          const frag = document.createDocumentFragment();
          const parts = ('' + cell).split('\n');
          for (let i=0;i<parts.length;i++) {
            frag.appendChild(document.createTextNode(parts[i]));
            if (i < parts.length-1) frag.appendChild(document.createElement('br'));
          }
          td.appendChild(frag);
          tr.appendChild(td);
        }
        if (isEmpty) tr.classList.add('empty');
        tbody.appendChild(tr);
      }

      table.appendChild(thead);
      table.appendChild(tbody);
      tableWrap.appendChild(table);

      // If we limited rows, show a small note
      if (endRow < data.length) {
        const note = document.createElement('div');
        note.className = 'small';
        note.style.padding = '8px';
        note.textContent = 'Showing ' + (endRow - startRow) + ' of ' + (data.length - startRow) + ' rows.';
        tableWrap.appendChild(note);
      }
    }

    function safeParseAndRender() {
      errorDiv.textContent = '';
      const text = input.value;
      const delimiter = delimiterEl.value || ',';
      const trimUnquoted = trimUnquotedEl.checked;
      const hasHeader = hasHeaderEl.checked;
      const maxRows = parseInt(maxRowsEl.value,10) || 0;
      try {
        const data = parseCSV(text, delimiter, {trimUnquoted});
        renderTable(data, {hasHeader, maxRows});
      } catch (err) {
        errorDiv.textContent = 'Error: ' + err.message;
        tableWrap.innerHTML = '';
      }
    }

    parseBtn.addEventListener('click', safeParseAndRender);
    clearBtn.addEventListener('click', function(){
      input.value = '';
      tableWrap.innerHTML = '';
      errorDiv.textContent = '';
    });
    pasteExample.addEventListener('click', function(){
      input.value = '"Name","Age","Notes"\n"Smith, John",30,"Likes ""quotes"" and new\nlines"\nDoe,25,"No notes"\n"Trailing empty",,""\nUnquoted with spaces , 42 , "quoted"';
    });

    // Allow Ctrl+Enter to parse
    input.addEventListener('keydown', function(e){
      if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') { safeParseAndRender(); e.preventDefault(); }
    });

    // Try parse on load if textarea has content
    if (input.value.trim() !== '') safeParseAndRender();

  })();
  </script>
</body>
</html>

If you find any specific CSV that still causes trouble, paste it into the textarea and I’ll analyze and adapt the parser for that edge case.
